// Prepare 3 RAG queries
const webhookData = $('1. Webhook Entree').item.json.body;
const cabinetData = $('2. Verifier Cabinet').item.json[0];
const type_acte = webhookData.type_acte;
const cabinet_id = cabinetData.cabinet_id;

return [
  {
    json: {
      query_type: 'clauses',
      search_text: `clauses ${type_acte} modele acte formulation`,
      cabinet_id,
      type_acte,
      nb_resultats: 5
    }
  },
  {
    json: {
      query_type: 'obligations',
      search_text: `obligations legales conditions validite ${type_acte}`,
      cabinet_id,
      type_acte: null,
      nb_resultats: 5
    }
  },
  {
    json: {
      query_type: 'tarifs',
      search_text: `tarifs frais notariaux ${type_acte} honoraires`,
      cabinet_id,
      type_acte: null,
      nb_resultats: 3
    }
  }
];

